const _gelidburn_oil = {title: "Gelidburn oil", jsx: <><h2 id="eq-poison-gelidburn_oil-gelidburn-oil">Gelidburn oil</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 24</Link></p>
<p><strong>Price</strong> 75 gp; <strong>Weight</strong> &mdash;</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="eq-poison-gelidburn_oil--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={8} to="/rule/poison"><IonIcon aria-label="Poison" icon="/icons/poison-bottle.svg" /></ThLink><th scope="row">Type</th><td colSpan={3}>Injury</td></tr><tr><th scope="row">Save DC</th><td colSpan={3}>Fort 12</td></tr><tr><th scope="row">Onset</th><td colSpan={3}>immediate</td></tr><tr><th scope="row">Frequency</th><td colSpan={3}>1/round for 4 rounds</td></tr><tr><th scope="row">Effect</th><td colSpan={3}>1d3 fire, 1d3 cold, and <Link to="/misc/staggered">staggered</Link> 1 round</td></tr><tr><th scope="row">Cure</th><td colSpan={3}>1 save</td></tr></tbody></table></ScrollContainer></div><p>This greasy pale-blue liquid delivers a shocking sensation that is both freezing cold and searing hot. Gelidburn oil is popular among pickpockets looking to stab, snatch, and run.</p>
</>};
const _goblins_eye = {title: "Goblin's eye", jsx: <><h2 id="eq-poison-goblins_eye-goblins-eye">Goblin's eye</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 144</Link></p>
<p><strong>Price</strong> 75 gp; <strong>Weight</strong> &mdash;</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="eq-poison-goblins_eye--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={8} to="/rule/poison"><IonIcon aria-label="Poison" icon="/icons/poison-bottle.svg" /></ThLink><th scope="row">Type</th><td colSpan={3}>Ingested</td></tr><tr><th scope="row">Save DC</th><td colSpan={3}>Fort 13</td></tr><tr><th scope="row">Onset</th><td colSpan={3}>1 minute</td></tr><tr><th scope="row">Frequency</th><td colSpan={3}>1/minute for 6 minutes</td></tr><tr><th scope="row">Effect</th><td colSpan={3}>1 <Link to="/rule/con_damage">Con damage</Link> and the creature is <Link to="/misc/nauseated">nauseated</Link> for 1 minute</td></tr><tr><th scope="row">Cure</th><td colSpan={3}>1 save</td></tr></tbody></table></ScrollContainer></div><p>These bright red seeds feature a single black dot each, giving them a superficial resemblance to an eye. The bright colors of the seeds make them attractive to certain animals, as well as those unfamiliar with wilderness lore. A character who succeeds at a DC 15 Knowledge (nature) or Survival check identifies the seed as poisonous. In some places, the seeds are used as jewelry.</p>
</>};
const _vampires_kiss = {title: "Vampire's kiss", jsx: <><h2 id="eq-poison-vampires_kiss-vampires-kiss">Vampire's kiss</h2>
<p><strong>Sources</strong> <Link to="/source/alchemy_manual">Alchemy Manual pg. 9</Link></p>
<p><strong>Price</strong> 75 gp; <strong>Weight</strong> &mdash;</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="eq-poison-vampires_kiss--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={7} to="/rule/poison"><IonIcon aria-label="Poison" icon="/icons/poison-bottle.svg" /></ThLink><th scope="row">Type</th><td colSpan={3}>Injury</td></tr><tr><th scope="row">Save DC</th><td colSpan={3}>Fort 15</td></tr><tr><th scope="row">Onset</th><td colSpan={3}>immediate</td></tr><tr><th scope="row">Frequency</th><td colSpan={3}>1/round for 2 rounds</td></tr><tr></tr><tr><th scope="row">Cure</th><td colSpan={3}>1 save</td></tr></tbody></table></ScrollContainer></div><p><strong><Link to="/rule/spontaneous_alchemy">Spontaneous Alchemy</Link> Recipe</strong> (6 gold + 50 myrrh + 30 quicksilver)/distillation; <strong>Craft</strong> DC 15<br/><strong>Time</strong> 1 day; <strong>Tools</strong> <Link to="/eq-misc/retort">retort</Link>; <strong>Type</strong> poison</p>
</>};
const _confabulation_powder = {title: "Confabulation powder", jsx: <><h2 id="eq-poison-confabulation_powder-confabulation-powder">Confabulation powder</h2>
<p><strong>Sources</strong> <Link to="/source/alchemy_manual">Alchemy Manual pg. 11</Link></p>
<p><strong>Price</strong> 80 gp; <strong>Weight</strong> &mdash;</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="eq-poison-confabulation_powder--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={9} to="/rule/poison"><IonIcon aria-label="Poison" icon="/icons/poison-bottle.svg" /></ThLink><th scope="row">Type</th><td colSpan={3}>Inhaled</td></tr><tr><th scope="row">Save DC</th><td colSpan={3}>Fort 18</td></tr><tr><th scope="row">Onset</th><td colSpan={3}>immediate</td></tr><tr><th scope="row">Frequency</th><td colSpan={3}>1/minute for 2 minutes</td></tr><tr><th scope="row">Initial Effect</th><td colSpan={3}><Link to="/misc/staggered">staggered</Link> for 1 minute</td></tr><tr><th scope="row">Secondary Effect</th><td colSpan={3}>If already staggered, <Link to="/misc/stunned">stunned</Link>, or <Link to="/misc/unconscious">unconscious</Link>, the victim becomes highly suggestible. If an event (whether true or false) is described to him, he unconsciously fabricates a detailed memory of the event, filling in any gaps in the description with his own best guesses. The confabulated memory can be disbelieved with a successful DC 18 Will save the first time it is recalled, but if the save fails, the victim treats it as completely genuine thereafter. All confabulated memories can be removed with a restoration or heal spell</td></tr><tr><th scope="row">Cure</th><td colSpan={3}>1 save</td></tr></tbody></table></ScrollContainer></div><p><strong><Link to="/rule/spontaneous_alchemy">Spontaneous Alchemy</Link> Recipe</strong> (20 quicksilver + 15 cytillesh spores)/digestion; <strong>Craft</strong> DC 18<br/><strong>Time</strong> 1 day; <strong>Tools</strong> heat source; <strong>Type</strong> poison</p>
</>};
